css:
.contract-doc { font-family: Georgia, 'Times New Roman', serif; font-size: 10.5pt; line-height: 1.45; color: #000; }
.contract-doc h1 { font-size: 13pt; text-align: center; margin: 14px 0 8px; page-break-after: avoid; }
.contract-doc h2, .contract-doc h3 { font-size: 11pt; margin: 12px 0 6px; page-break-after: avoid; }
.contract-doc p { margin: 5px 0; text-align: justify; }
.contract-doc table.ct-table { width: 100%; border-collapse: collapse; margin: 8px 0; page-break-inside: avoid; }
.contract-doc table.ct-table td { border: 1px solid #444; padding: 4px 7px; vertical-align: top; font-size: 10pt; }
.contract-doc .ct-blank { display: inline-block; border-bottom: 1px solid #000; min-height: 1em; white-space: nowrap; overflow: hidden; }
.contract-doc .ct-cb { font-size: 12pt; }
